package com.enterprise.spark.gpu.integration import com.enterprise.spark.gpu.core.SparkGpuTestBase
import com.enterprise.spark.gpu.core.pipeline.MachineLearningPipelineExecutor
import com.enterprise.spark.gpu.benchmarking.PerformanceBenchmarkService
import com.enterprise.spark.gpu.reporting.ReportGenerationService
import org.scalatest.time.{Minutes, Span}
import java.io.File /** * Comprehensive end-to-end integration test suite. * * This test suite validates the complete GPU-accelerated Spark pipeline * from data generation through final report generation. It ensures: * - All modules work together seamlessly * - Real data processing with measurable performance benefits * - Professional report generation with actual results * - Error handling and resource management across modules * - Performance validation with realistic datasets * * These tests use real Spark operations and actual GPU acceleration * (when available) to provide authentic validation of the system. */
class EndToEndIntegrationTest extends SparkGpuTestBase { // Increase timeout for integration tests implicit val patience = org.scalatest.time.Patience(Span(10, Minutes)) test("should execute complete end-to-end pipeline with all modules") { val (results, totalExecutionTime) = measureExecutionTime { // Step 1: Execute ML Pipeline logger.info("=== Integration Test: Executing ML Pipeline ===") val pipelineExecutor = new MachineLearningPipelineExecutor() val pipelineSummary = pipelineExecutor.executeComplete() // Step 2: Execute Performance Benchmarks logger.info("=== Integration Test: Executing Performance Benchmarks ===") val benchmarkService = new PerformanceBenchmarkService() val benchmarkConfig = PerformanceBenchmarkService.BenchmarkConfig( iterations = 2, // Reduced for integration test speed warmupIterations = 1, datasetSizes = Seq(50000, 100000), // Smaller datasets for testing enableGpuComparison = true, outputDirectory = "test-reports/benchmarks" ) val benchmarkResults = benchmarkService.executeComprehensiveBenchmarks(benchmarkConfig) // Step 3: Generate Comprehensive Reports logger.info("=== Integration Test: Generating Reports ===") val reportService = new ReportGenerationService() val reportConfig = ReportGenerationService.ReportConfig( outputDirectory = "test-reports", generateCharts = true, includeExecutiveSummary = true, includeTechnicalDetails = true ) val reportSummary = reportService.generateComprehensiveReports( pipelineSummary, Some(benchmarkResults), reportConfig ) (pipelineSummary, benchmarkResults, reportSummary) } val (pipelineSummary, benchmarkResults, reportSummary) = results // Validate Pipeline Results validatePipelineResults(pipelineSummary) // Validate Benchmark Results validateBenchmarkResults(benchmarkResults) // Validate Report Generation validateReportGeneration(reportSummary) // Validate Overall Performance validateOverallPerformance(totalExecutionTime, pipelineSummary.dataGenerationSummary.totalRecords) logTestPerformance("Complete End-to-End Integration", totalExecutionTime, pipelineSummary.dataGenerationSummary.totalRecords) } test("should handle GPU availability detection across all modules") { val pipelineExecutor = new MachineLearningPipelineExecutor() val pipelineSummary = pipelineExecutor.executeComplete() val benchmarkService = new PerformanceBenchmarkService() val benchmarkConfig = PerformanceBenchmarkService.BenchmarkConfig( iterations = 1, datasetSizes = Seq(10000), enableGpuComparison = true ) val benchmarkResults = benchmarkService.executeComprehensiveBenchmarks(benchmarkConfig) // GPU availability should be consistent across modules pipelineSummary.gpuAccelerationEnabled shouldEqual benchmarkResults.gpuAvailable // If GPU is available, benchmark should include GPU results if (benchmarkResults.gpuAvailable) { val gpuBenchmarks = benchmarkResults.benchmarkResults.filter(_.executionMode == "GPU") gpuBenchmarks should not be empty logger.info(s"GPU benchmarks executed: ${gpuBenchmarks.length} operations") } else { logger.info("GPU not available - CPU-only benchmarks executed") } } test("should generate professional reports with real performance data") { // Execute pipeline to get real data val pipelineExecutor = new MachineLearningPipelineExecutor() val pipelineSummary = pipelineExecutor.executeComplete() // Execute benchmarks to get performance comparisons val benchmarkService = new PerformanceBenchmarkService() val benchmarkResults = benchmarkService.executeComprehensiveBenchmarks( PerformanceBenchmarkService.BenchmarkConfig( iterations = 1, datasetSizes = Seq(25000), outputDirectory = "test-reports/integration-benchmarks" ) ) // Generate reports val reportService = new ReportGenerationService() val reportSummary = reportService.generateComprehensiveReports( pipelineSummary, Some(benchmarkResults), ReportGenerationService.ReportConfig( outputDirectory = "test-reports/integration", generateCharts = true, includeExecutiveSummary = true ) ) // Validate report files exist and contain real data reportSummary.generatedFiles should not be empty reportSummary.generatedFiles.foreach { filePath => assertPathExists(filePath) // Verify files are not empty val file = new File(filePath) file.length() should be > 0L } // Validate HTML report contains actual performance data val htmlContent = scala.io.Source.fromFile(reportSummary.htmlReportPath).mkString htmlContent should include("GPU-Accelerated Apache Spark Performance Report") htmlContent should include(pipelineSummary.dataGenerationSummary.totalRecords.toString) htmlContent should include("Model Performance Comparison") // If GPU benchmarks were run, report should include speedup information if (benchmarkResults.gpuAvailable) { htmlContent should include("CPU vs GPU Performance Comparison") } } test("should demonstrate measurable performance improvements with larger datasets") { // Test with progressively larger datasets to show scaling benefits val datasetSizes = Seq(25000, 50000, 100000) val performanceResults = scala.collection.mutable.ListBuffer[(Int, Long, Double)]() datasetSizes.foreach { datasetSize => logger.info(s"Testing performance with dataset size: $datasetSize") val (executionTime, throughput) = measureExecutionTime { val pipelineExecutor = new MachineLearningPipelineExecutor() val summary = pipelineExecutor.executeComplete() // Calculate throughput val recordsPerSecond = (summary.dataGenerationSummary.totalRecords * 1000.0) / summary.totalExecutionTimeMs recordsPerSecond } performanceResults += ((datasetSize, executionTime._2, executionTime._1)) } // Validate that throughput scales reasonably performanceResults.foreach { case (size, time, throughput) => throughput should be >= 100.0 // At least 100 records/second logger.info(s"Dataset size: $size, Time: ${time}ms, Throughput: ${throughput.formatted("%.2f")} records/sec") } // Larger datasets should not have dramatically worse throughput (allowing for overhead) val throughputs = performanceResults.map(_._3) val minThroughput = throughputs.min val maxThroughput = throughputs.max // Throughput should not degrade by more than 50% across dataset sizes minThroughput should be >= (maxThroughput * 0.5) } test("should handle error conditions gracefully across all modules") { // This test validates error handling and resource cleanup // Test with invalid configuration (should handle gracefully) val benchmarkService = new PerformanceBenchmarkService() // Test with very small dataset (edge case) val edgeCaseConfig = PerformanceBenchmarkService.BenchmarkConfig( iterations = 1, datasetSizes = Seq(10), // Very small dataset enableGpuComparison = false // Disable GPU to test CPU-only path ) val benchmarkResults = benchmarkService.executeComprehensiveBenchmarks(edgeCaseConfig) // Should complete without errors even with edge case configuration benchmarkResults.benchmarkResults should not be empty benchmarkResults.totalExecutionTimeMs should be > 0L // All benchmark results should have valid metrics benchmarkResults.benchmarkResults.foreach { result => result.averageTimeMs should be > 0L result.datasetSize should be > 0L result.throughputRecordsPerSecond should be >= 0L } } test("should validate data quality and consistency across pipeline stages") { val pipelineExecutor = new MachineLearningPipelineExecutor() val pipelineSummary = pipelineExecutor.executeComplete() // Validate data generation quality pipelineSummary.dataGenerationSummary.validationResults.valid shouldBe true pipelineSummary.dataGenerationSummary.totalRecords should be > 0 // Validate taxi analysis results are realistic val taxiResults = pipelineSummary.taxiAnalysisResults taxiResults.totalTrips should be > 0L taxiResults.averageFare should be > 0.0 taxiResults.averageFare should be < 1000.0 // Reasonable fare range taxiResults.peakHours should not be empty // Validate model training results are within expected ranges val modelResults = pipelineSummary.modelTrainingResults // Both models should have been trained modelResults.randomForestMetrics should not be null modelResults.linearRegressionMetrics should not be null // Model metrics should be within valid ranges assertModelMetrics( rmse = modelResults.randomForestMetrics.rmse, mae = modelResults.randomForestMetrics.mae, r2 = modelResults.randomForestMetrics.r2, maxRmse = 1000000.0, // Reasonable for housing prices maxMae = 500000.0, minR2 = -1.0 // R² can be negative for very poor models ) assertModelMetrics( rmse = modelResults.linearRegressionMetrics.rmse, mae = modelResults.linearRegressionMetrics.mae, r2 = modelResults.linearRegressionMetrics.r2, maxRmse = 1000000.0, maxMae = 500000.0, minR2 = -1.0 ) } /** * Validates pipeline execution results. */ private def validatePipelineResults(pipelineSummary: com.enterprise.spark.gpu.core.pipeline.PipelineExecutionSummary): Unit = { // Basic validation pipelineSummary should not be null pipelineSummary.totalExecutionTimeMs should be > 0L pipelineSummary.dataGenerationSummary should not be null pipelineSummary.taxiAnalysisResults should not be null pipelineSummary.modelTrainingResults should not be null // Data generation validation pipelineSummary.dataGenerationSummary.totalRecords should be > 0 pipelineSummary.dataGenerationSummary.validationResults.valid shouldBe true // Model training validation val rfMetrics = pipelineSummary.modelTrainingResults.randomForestMetrics val lrMetrics = pipelineSummary.modelTrainingResults.linearRegressionMetrics rfMetrics.trainingTimeMs should be > 0L lrMetrics.trainingTimeMs should be > 0L // Models should be saved assertPathExists("models/random_forest_model") assertPathExists("models/linear_regression_model") } /** * Validates benchmark execution results. */ private def validateBenchmarkResults(benchmarkResults: com.enterprise.spark.gpu.benchmarking.BenchmarkResults): Unit = { benchmarkResults should not be null benchmarkResults.benchmarkResults should not be empty benchmarkResults.totalExecutionTimeMs should be > 0L // Validate individual benchmark results benchmarkResults.benchmarkResults.foreach { result => result.averageTimeMs should be > 0L result.minTimeMs should be > 0L result.maxTimeMs should be >= result.minTimeMs result.datasetSize should be > 0L result.iterations should be > 0 result.throughputRecordsPerSecond should be >= 0L } // Should have CPU results at minimum val cpuResults = benchmarkResults.benchmarkResults.filter(_.executionMode == "CPU") cpuResults should not be empty // If GPU is available, should have GPU results if (benchmarkResults.gpuAvailable) { val gpuResults = benchmarkResults.benchmarkResults.filter(_.executionMode == "GPU") gpuResults should not be empty } } /** * Validates report generation results. */ private def validateReportGeneration(reportSummary: com.enterprise.spark.gpu.reporting.ReportGenerationSummary): Unit = { reportSummary should not be null reportSummary.generatedFiles should not be empty reportSummary.generationTimeMs should be > 0L // Validate HTML report exists and is not empty assertPathExists(reportSummary.htmlReportPath) val htmlFile = new File(reportSummary.htmlReportPath) htmlFile.length() should be > 1000L // Should be substantial content // Validate all generated files exist reportSummary.generatedFiles.foreach { filePath => assertPathExists(filePath) val file = new File(filePath) file.length() should be > 0L } } /** * Validates overall performance characteristics. */ private def validateOverallPerformance(executionTimeMs: Long, recordsProcessed: Long): Unit = { // Integration test should complete within reasonable time executionTimeMs should be <= 600000L // 10 minutes maximum // Should process records at reasonable throughput val recordsPerSecond = (recordsProcessed * 1000.0) / executionTimeMs recordsPerSecond should be >= 50.0 // At least 50 records/second for integration test logger.info(s"Integration test performance: ${recordsPerSecond.formatted("%.2f")} records/second") }
}